  ('aboriginal-4ece01bd-moex-00130', 'aboriginal-4ece01bd', 'aboriginal-4ece01bd-moex-111-6ed013db', 'sub-aboriginal-4ece01bd-08', NULL, 'single_choice', '為照顧原住民族長者，提供原住民族長者良好的高齡生活品質，原住民族委員會依據長期照顧十年計 畫2.0第6章原住民族長期照顧專章於原住民族地區及都會區廣設文化健康站，請問下列那一項非文 化健康站所提供的服務項目？', '["失智症照顧", "簡易健康照顧服務", "延緩老化失能活動", "營養餐飲服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:38+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "612", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "土木工程"}'::jsonb, NULL),
  ('aboriginal-4ece01bd-moex-00131', 'aboriginal-4ece01bd', 'aboriginal-4ece01bd-moex-111-6ed013db', 'sub-aboriginal-4ece01bd-08', NULL, 'single_choice', '為協助原住民族社會發展，原住民族委員會設置原住民族綜合發展基金提供原住民經濟貸款，下列那 一項非可貸款的項目？', '["原住民購屋貸款", "原住民經濟貸款", "原住民青年創業貸款", "原住民微型經濟活動貸款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:38+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "612", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "土木工程"}'::jsonb, NULL),
