  ('aboriginal-4ece01bd-moex-00134', 'aboriginal-4ece01bd', 'aboriginal-4ece01bd-moex-111-6ed013db', 'sub-aboriginal-4ece01bd-08', NULL, 'single_choice', '原住民民族別的認定需經行政院核定，下列那一個民族尚未被政府列入法定原住民族？', '["撒奇萊雅族", "拉阿魯哇族", "馬卡道族", "卡那卡那富族"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:38+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "612", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "土木工程"}'::jsonb, NULL),
  ('aboriginal-4ece01bd-moex-00135', 'aboriginal-4ece01bd', 'aboriginal-4ece01bd-moex-111-6ed013db', 'sub-aboriginal-4ece01bd-08', NULL, 'single_choice', '政府辦理原住民族經濟發展業務、輔導事業機構、住宅之興辦、租售、建購及修繕業務可由下列那一 種基金支應所需之經費？', '["原住民族文化事業基金", "原住民族綜合發展基金", "原住民族社會發展基金", "原住民族地區建設基金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:38+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "612", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "土木工程"}'::jsonb, NULL),
  ('aboriginal-4ece01bd-moex-00136', 'aboriginal-4ece01bd', 'aboriginal-4ece01bd-moex-111-6ed013db', 'sub-aboriginal-4ece01bd-08', NULL, 'single_choice', '行政院為統合原住民族政策，保障原住民族權益，辦理原住民族業務，於1996年12月1日成立原住 民族委員會，依據原住民族委員會組織法，下列敘述何者錯誤？', '["設置主任委員1人，由原住民擔任", "設置副主任委員3人，其中2人應由原住民擔任", "設置委員19人至29人，其中原住民族各族代表應至少1人依聘用人員聘用條例聘用，且應有二分之 一以上人數具原住民身分，其聘期隨主任委員異動而更易", "原住民族委員會簡任、薦任、委任各官等人員具原住民身分者，均不得低於百分之七十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:38+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "612", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "土木工程"}'::jsonb, NULL),
  ('aboriginal-4ece01bd-moex-00137', 'aboriginal-4ece01bd', 'aboriginal-4ece01bd-moex-111-6ed013db', 'sub-aboriginal-4ece01bd-08', NULL, 'single_choice', '依據原住民族語言發展法之規定，下列敘述何者錯誤？', '["原住民山地鄉、平地鄉之鄉公所，可以以該地區之原住民族語言書寫公文", "花蓮火車站可以使用阿美族、太魯閣族語進行播音", "為因應原住民學生學習的需求，花蓮的國民中小學可以以阿美族語或是太魯閣族語進行教學", "原住民至法院出庭陳述意見時，可以以原民族語言陳述意見，但需自行聘請通譯傳譯之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:38+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "612", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "土木工程"}'::jsonb, NULL),
  ('aboriginal-4ece01bd-moex-00138', 'aboriginal-4ece01bd', 'aboriginal-4ece01bd-moex-111-6ed013db', 'sub-aboriginal-4ece01bd-08', NULL, 'single_choice', '依據原住民族基本法，下列敘述何者錯誤？', '["原住民得在原住民族地區從事獵捕野生動物、採集野生植物、礦物、土石等營利行為", "當政府或私人於原住民族土地從事土地開發時，原住民族或部落得拒絕之", "當政府於原住民族地區劃設國家公園、國家級風景特定區、林業區、生態保育區時，原住民族得拒 絕之", "當政府欲於原住民族地區內存放有害物質時，原住民族得拒絕之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:38+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "612", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "土木工程"}'::jsonb, NULL)
